-      // in x86. Reordering them into [fsub,fadd] blocks this pattern. So we
-      // need to take into account their order when looking for the most used
-      // order.
-      unsigned Opcode0 = E->getOpcode();
-      unsigned Opcode1 = E->getAltOpcode();
