-  InstructionCost getBuildVectorCost(ArrayRef<Value *> VL, Value *Root) {
-    if ((!Root && allConstant(VL)) || all_of(VL, IsaPred<UndefValue>))
-      return TTI::TCC_Free;
-    auto *VecTy = getWidenedType(ScalarTy, VL.size());
