-          CastOpcode = IsSigned ? Instruction::SExt : Instruction::ZExt;
-        return TTI.getCastInstrCost(
-            CastOpcode, VectorType::get(ScalarTy, VecTy->getElementCount()),
-            VecTy, TTI::CastContextHint::None, CostKind);
-      }
-      return TTI::TCC_Free;
-    };
-    if (!V1 && !V2 && !P2.isNull()) {
