-        }
-        CommonVF = VF;
-      }
-      ExtraCost += GetNodeMinBWAffectedCost(
-          *E1, std::min(CommonVF, E1->getVectorFactor()));
-      V1 = Constant::getNullValue(getWidenedType(ScalarTy, CommonVF));
